#!/usr/bin/env bash
# Build a high-quality macOS icon (assets/icon.icns) from assets/icon.png using
# the native `iconutil`. Pillow's ICNS export is limited, so on macOS we prefer
# this. Safe to run repeatedly. Requires assets/icon.png (generated by
# packaging/make_icon.py).
set -euo pipefail

ROOT="$(cd "$(dirname "$0")/.." && pwd)"
PNG="$ROOT/assets/icon.png"
ICNS="$ROOT/assets/icon.icns"

if [ ! -f "$PNG" ]; then
  echo "Missing $PNG — run: python3 packaging/make_icon.py" >&2
  exit 1
fi
if ! command -v iconutil >/dev/null 2>&1; then
  echo "iconutil not found (are you on macOS?). Keeping existing icon.icns." >&2
  exit 0
fi

TMP="$(mktemp -d)/icon.iconset"
mkdir -p "$TMP"
gen() { sips -z "$2" "$2" "$PNG" --out "$TMP/$1" >/dev/null; }

gen "icon_16x16.png"        16
gen "icon_16x16@2x.png"     32
gen "icon_32x32.png"        32
gen "icon_32x32@2x.png"     64
gen "icon_128x128.png"      128
gen "icon_128x128@2x.png"   256
gen "icon_256x256.png"      256
gen "icon_256x256@2x.png"   512
gen "icon_512x512.png"      512
gen "icon_512x512@2x.png"   1024

iconutil -c icns "$TMP" -o "$ICNS"
echo "Wrote $ICNS"
